package com.trademaster.ims.mobile.checkout.service;
import com.trademaster.ims.mobile.auth.model.CustomerAccount;import com.trademaster.ims.mobile.auth.repository.CustomerAccountRepository;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;import com.trademaster.ims.mobile.offers.service.OfferPricingService;import com.trademaster.ims.mobile.auth.security.CustomerAuthentication;import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.checkout.dto.CheckoutDtos.*;import com.trademaster.ims.mobile.checkout.model.*;import com.trademaster.ims.mobile.checkout.repository.*;import com.trademaster.ims.mobile.shopping.model.*;import com.trademaster.ims.mobile.shopping.repository.*;import com.trademaster.ims.model.*;import com.trademaster.ims.repository.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.http.HttpStatus;import org.springframework.security.core.Authentication;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;import java.nio.charset.StandardCharsets;import java.security.*;import java.time.*;import java.util.*;
@Service @Transactional public class MobileCheckoutService{
 private final CustomerAddressRepository addresses;private final DeliveryMethodRepository methods;private final CheckoutReviewRepository reviews;private final CustomerOrderRepository orders;private final CustomerOrderItemRepository orderItems;private final CustomerOrderStatusHistoryRepository history;private final CustomerCartRepository carts;private final CustomerCartItemRepository cartItems;private final ProductRepository products;private final ProductVariationRepository variations;private final InventoryRepository inventory;private final CustomerAccountRepository accounts;private final OfferPricingService offerPricing;@Autowired(required=false) private CustomerNotificationService notifications;
 public MobileCheckoutService(CustomerAddressRepository a,DeliveryMethodRepository m,CheckoutReviewRepository r,CustomerOrderRepository o,CustomerOrderItemRepository oi,CustomerOrderStatusHistoryRepository h,CustomerCartRepository c,CustomerCartItemRepository ci,ProductRepository p,ProductVariationRepository v,InventoryRepository i,CustomerAccountRepository ac,OfferPricingService op){addresses=a;methods=m;reviews=r;orders=o;orderItems=oi;history=h;carts=c;cartItems=ci;products=p;variations=v;inventory=i;accounts=ac;offerPricing=op;}
 public long account(Authentication a){if(a instanceof CustomerAuthentication c)return c.accountId();throw err(HttpStatus.UNAUTHORIZED,"AUTHENTICATION_REQUIRED","Customer authentication is required.");}
 public List<AddressResponse>listAddresses(long a){return addresses.findByAccountIdAndActiveTrueOrderByDefaultAddressDescIdAsc(a).stream().map(this::address).toList();}public AddressResponse getAddress(long a,long id){return address(ownedAddress(a,id));}
 public AddressResponse createAddress(long a,AddressRequest q){if(addresses.countByAccountIdAndActiveTrue(a)>=10)throw err(HttpStatus.CONFLICT,"ADDRESS_LIMIT_REACHED","A maximum of 10 active addresses is allowed.");CustomerAddress x=new CustomerAddress();x.setAccountId(a);copy(x,q);if(q.defaultAddress()||addresses.countByAccountIdAndActiveTrue(a)==0)makeDefault(a,x);return address(addresses.save(x));}
 public AddressResponse updateAddress(long a,long id,AddressRequest q){CustomerAddress x=ownedAddress(a,id);boolean wasDefault=x.isDefaultAddress();copy(x,q);if(q.defaultAddress())makeDefault(a,x);else if(wasDefault)x.setDefaultAddress(true);return address(addresses.save(x));}
 public void deleteAddress(long a,long id){CustomerAddress x=ownedAddress(a,id);boolean was=x.isDefaultAddress();x.setActive(false);x.setDefaultAddress(false);addresses.save(x);if(was)addresses.findByAccountIdAndActiveTrueOrderByDefaultAddressDescIdAsc(a).stream().findFirst().ifPresent(n->{n.setDefaultAddress(true);addresses.save(n);});}
 public AddressResponse setDefault(long a,long id){CustomerAddress x=ownedAddress(a,id);makeDefault(a,x);return address(addresses.save(x));}
 public List<DeliveryMethodResponse>deliveryMethods(Long account,Long addressId){CustomerAddress a=addressId==null?null:ownedAddress(Objects.requireNonNull(account),addressId);return methods.findByActiveTrueOrderByChargeAsc().stream().map(m->delivery(m,a,null)).toList();}
 public ReviewResponse review(long account,ReviewRequest q){CustomerAddress a=ownedAddress(account,q.addressId());DeliveryMethod m=methods.findByIdAndActiveTrue(q.deliveryMethodId()).orElseThrow(()->err(HttpStatus.BAD_REQUEST,"DELIVERY_METHOD_NOT_AVAILABLE","Delivery method is unavailable."));Calculation c=calculate(account,a,m);CheckoutReview r=new CheckoutReview();r.setId(UUID.randomUUID().toString());r.setAccountId(account);r.setAddressId(a.getId());r.setDeliveryMethodId(m.getId());r.setFingerprint(c.fingerprint);r.setSubtotal(c.subtotal);r.setTax(c.tax);r.setDelivery(c.delivery);r.setTotal(c.total);r.setExpiresAt(Instant.now().plusSeconds(900));reviews.save(r);return response(r,a,m,c);}
 public OrderConfirmation submit(long account,SubmitRequest q){Optional<CustomerOrder> prior=orders.findByAccountIdAndIdempotencyKey(account,q.idempotencyKey());if(prior.isPresent()){if(!prior.get().getReviewId().equals(q.reviewId()))throw err(HttpStatus.CONFLICT,"IDEMPOTENCY_CONFLICT","Idempotency key was used for a different review.");notifyOrderCreated(prior.get());return confirmation(prior.get());}CheckoutReview r=reviews.findByIdAndAccountId(q.reviewId(),account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"CHECKOUT_REVIEW_NOT_FOUND","Checkout review was not found."));if(r.getExpiresAt().isBefore(Instant.now()))throw err(HttpStatus.CONFLICT,"CHECKOUT_REVIEW_EXPIRED","Checkout review expired. Refresh it before submitting.");if(r.isConsumed())throw err(HttpStatus.CONFLICT,"CHECKOUT_REVIEW_EXPIRED","Checkout review has already been used.");CustomerAddress a=ownedAddress(account,r.getAddressId());DeliveryMethod m=methods.findByIdAndActiveTrue(r.getDeliveryMethodId()).orElseThrow(()->err(HttpStatus.CONFLICT,"DELIVERY_METHOD_NOT_AVAILABLE","Delivery method is unavailable."));Calculation c=calculate(account,a,m);if(!c.blocking.isEmpty())throw err(HttpStatus.CONFLICT,"CART_CHANGED",c.blocking.get(0));if(!r.getFingerprint().equals(c.fingerprint))throw err(HttpStatus.CONFLICT,"CART_CHANGED","Cart, price, or availability changed. Request a new review.");if(r.getTotal().compareTo(c.total)!=0)throw err(HttpStatus.CONFLICT,"TOTAL_CHANGED","Checkout total changed. Request a new review.");CustomerOrder o=new CustomerOrder();o.setOrderNumber(orderNumber());o.setAccountId(account);o.setIdempotencyKey(q.idempotencyKey());o.setReviewId(r.getId());o.setSubtotal(c.subtotal);o.setTax(c.tax);o.setDelivery(c.delivery);o.setTotal(c.total);o.setRecipient(a.getRecipientName());o.setPhone(a.getPhone());o.setAddressSnapshot(addressText(a));o.setDeliverySnapshot(m.getName()+" ("+m.getMinDays()+"-"+m.getMaxDays()+" days)");o.setNote(trim(q.customerNote()));o.setSubmittedAt(Instant.now());o=orders.saveAndFlush(o);for(Line l:c.lines){CustomerOrderItem i=new CustomerOrderItem();i.setOrderId(o.getId());i.setProductId(l.product.getId());i.setVariationId(l.variation==null?null:l.variation.getVariationId());i.setProductName(l.product.getProductName());i.setProductCode(l.variation==null?l.product.getProductCode():l.variation.getSku());i.setVariationName(l.variation==null?null:l.variation.getVariationName());i.setImageUrl(l.variation!=null&&l.variation.getImageUrl()!=null?l.variation.getImageUrl():l.product.getImageUrl());i.setUnitPrice(l.price);i.setQuantity(l.item.getQuantity());i.setTaxRate(l.rate);i.setTaxAmount(l.tax);i.setLineSubtotal(l.subtotal);orderItems.save(i);}CustomerOrderStatusHistory h=new CustomerOrderStatusHistory();h.setOrderId(o.getId());h.setStatus(o.getStatus().name());history.save(h);r.setConsumed(true);reviews.save(r);cartItems.deleteByCartId(c.cart.getId());notifyOrderCreated(o);return confirmation(o);}
 private void notifyOrderCreated(CustomerOrder o){if(notifications!=null)notifications.orderCreated(o.getAccountId(),o.getOrderNumber(),o.getTotal(),"BDT");}
 private Calculation calculate(long account,CustomerAddress a,DeliveryMethod m){CustomerCart cart=carts.findByCustomerAccountIdAndStatus(account,CustomerCart.Status.ACTIVE).orElseThrow(()->err(HttpStatus.BAD_REQUEST,"CART_EMPTY","Cart is empty."));List<CustomerCartItem>stored=cartItems.findByCartIdOrderByIdAsc(cart.getId());if(stored.isEmpty())throw err(HttpStatus.BAD_REQUEST,"CART_EMPTY","Cart is empty.");List<Line>lines=new ArrayList<>();List<String>blocking=new ArrayList<>();BigDecimal sub=BigDecimal.ZERO,tax=BigDecimal.ZERO;StringBuilder fp=new StringBuilder();for(CustomerCartItem item:stored){Product p=products.findByIdAndStatus(item.getProductId(),Product.ProductStatus.ACTIVE).orElse(null);if(p==null){blocking.add("A product is no longer available.");continue;}ProductVariation v=null;if(item.getVariationId()!=null){v=variations.findById(item.getVariationId()).orElse(null);if(v==null||!v.isActive()||!Objects.equals(v.getProductId(),p.getId())){blocking.add("A selected variation is no longer available.");continue;}}long available=inventory.aggregateAvailableByProductIds(List.of(p.getId())).stream().findFirst().map(InventoryRepository.ProductStockTotal::getAvailableQuantity).orElse(0L);if(available<item.getQuantity()){blocking.add(p.getProductName()+" is out of stock or has insufficient availability.");continue;}BigDecimal price=offerPricing.bestPrice(p.getId(),p.getSellingPrice()).currentPrice().add(v==null?BigDecimal.ZERO:money(v.getAdditionalPrice())).setScale(2,RoundingMode.HALF_UP);BigDecimal line=price.multiply(BigDecimal.valueOf(item.getQuantity())).setScale(2,RoundingMode.HALF_UP);BigDecimal rate=money(p.getTaxRate());BigDecimal lt=line.multiply(rate).divide(BigDecimal.valueOf(100),2,RoundingMode.HALF_UP);lines.add(new Line(item,p,v,price,line,rate,lt));sub=sub.add(line);tax=tax.add(lt);fp.append(item.getProductId()).append(':').append(item.getVariationId()).append(':').append(item.getQuantity()).append(':').append(price).append(':').append(rate).append(';');}BigDecimal delivery=eligible(m,a,sub)?money(m.getCharge()).setScale(2,RoundingMode.HALF_UP):BigDecimal.ZERO;if(!eligible(m,a,sub))blocking.add("Delivery method is not eligible for this address or subtotal.");BigDecimal total=sub.add(tax).add(delivery).setScale(2,RoundingMode.HALF_UP);fp.append(a.getId()).append(':').append(m.getId()).append(':').append(delivery).append(':').append(total);return new Calculation(cart,lines,sub,tax,delivery,total,hash(fp.toString()),blocking);}
 private ReviewResponse response(CheckoutReview r,CustomerAddress a,DeliveryMethod m,Calculation c){List<ReviewItem>items=c.lines.stream().map(l->new ReviewItem(l.item.getId(),l.product.getId(),l.variation==null?null:l.variation.getVariationId(),l.product.getProductName(),l.variation==null?null:l.variation.getVariationName(),l.product.getImageUrl(),l.price,l.item.getQuantity(),l.subtotal,l.rate,l.tax,"In Stock",true)).toList();return new ReviewResponse(r==null?null:r.getId(),r==null?null:r.getExpiresAt(),c.fingerprint,items,c.subtotal,c.tax,c.delivery,BigDecimal.ZERO.setScale(2),c.total,"BDT",address(a),delivery(m,a,c.subtotal),c.blocking,List.of(),c.blocking.isEmpty());}
 private boolean eligible(DeliveryMethod m,CustomerAddress a,BigDecimal sub){return m.isActive()&&m.getCountry().equalsIgnoreCase(a.getCountry())&&(m.getDivision()==null||m.getDivision().equalsIgnoreCase(a.getDivision()))&&(m.getDistrict()==null||m.getDistrict().equalsIgnoreCase(a.getDistrict()))&&(m.getMinimum()==null||sub.compareTo(m.getMinimum())>=0)&&(m.getMaximum()==null||sub.compareTo(m.getMaximum())<=0);}
 private DeliveryMethodResponse delivery(DeliveryMethod m,CustomerAddress a,BigDecimal sub){boolean e=a==null||eligible(m,a,sub==null?BigDecimal.ZERO:sub);return new DeliveryMethodResponse(m.getId(),m.getCode(),m.getName(),m.getDescription(),m.getCharge(),m.getMinDays(),m.getMaxDays(),e,e?null:"Not eligible for the selected address or subtotal.");}
 private CustomerAddress ownedAddress(long a,long id){return addresses.findByIdAndAccountIdAndActiveTrue(id,a).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ADDRESS_NOT_FOUND","Address was not found or is inactive."));}private void makeDefault(long a,CustomerAddress selected){for(CustomerAddress x:addresses.findByAccountIdAndActiveTrueOrderByDefaultAddressDescIdAsc(a)){if(!Objects.equals(x.getId(),selected.getId())&&x.isDefaultAddress()){x.setDefaultAddress(false);addresses.save(x);}}selected.setDefaultAddress(true);}private void copy(CustomerAddress x,AddressRequest q){x.setLabel(trim(q.label()));x.setRecipientName(trim(q.recipientName()));x.setPhone(normalizePhone(q.phone()));x.setAddressLine1(trim(q.addressLine1()));x.setAddressLine2(trim(q.addressLine2()));x.setArea(trim(q.area()));x.setCity(trim(q.city()));x.setDistrict(trim(q.district()));x.setDivision(trim(q.division()));x.setPostalCode(trim(q.postalCode()));x.setCountry(trim(q.country()));x.setInstructions(trim(q.deliveryInstructions()));x.setDefaultAddress(q.defaultAddress());}
 private AddressResponse address(CustomerAddress x){return new AddressResponse(x.getId(),x.getLabel(),x.getRecipientName(),x.getPhone(),x.getAddressLine1(),x.getAddressLine2(),x.getArea(),x.getCity(),x.getDistrict(),x.getDivision(),x.getPostalCode(),x.getCountry(),x.getInstructions(),x.isDefaultAddress(),x.isActive());}private String addressText(CustomerAddress a){return String.join(", ",List.of(a.getAddressLine1(),a.getArea()==null?"":a.getArea(),a.getCity(),a.getDistrict(),a.getDivision(),a.getCountry())).replaceAll(", ,",",");}private String normalizePhone(String p){String n=p.replaceAll(" ","").replaceAll("-","");if(n.startsWith("+880"))return "0"+n.substring(4);if(n.startsWith("880"))return "0"+n.substring(3);return n;}private String trim(String s){return s==null||s.isBlank()?null:s.trim();}private BigDecimal money(BigDecimal v){return v==null?BigDecimal.ZERO:v;}private String hash(String v){try{return HexFormat.of().formatHex(MessageDigest.getInstance("SHA-256").digest(v.getBytes(StandardCharsets.UTF_8)));}catch(Exception e){throw new IllegalStateException(e);}}private String orderNumber(){return "TSS-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase();}private OrderConfirmation confirmation(CustomerOrder o){return new OrderConfirmation(o.getOrderNumber(),o.getSubmittedAt(),o.getStatus().name(),o.getPaymentStatus().name(),o.getTotal(),o.getAddressSnapshot(),o.getDeliverySnapshot(),"Your order is awaiting confirmation. Payment has not started.");}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);}private record Line(CustomerCartItem item,Product product,ProductVariation variation,BigDecimal price,BigDecimal subtotal,BigDecimal rate,BigDecimal tax){}private record Calculation(CustomerCart cart,List<Line>lines,BigDecimal subtotal,BigDecimal tax,BigDecimal delivery,BigDecimal total,String fingerprint,List<String>blocking){}
}

